import{_ as e,o as s,c as t,a2 as i}from"./chunks/framework.Bix3-HpO.js";const h=JSON.parse('{"title":"Blocks","description":"Spinoko Theme - Blocks","frontmatter":{"title":"Blocks","description":"Spinoko Theme - Blocks","weight":110,"extra":{"order":110},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/spinoko/blocks"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/spinoko/blocks"}],["meta",{"property":"og:title","content":"Blocks"}],["meta",{"property":"og:description","content":"Spinoko Theme - Blocks"}],["meta",{"name":"twitter:title","content":"Blocks"}],["meta",{"name":"twitter:description","content":"Spinoko Theme - Blocks"}]]},"headers":[],"relativePath":"docs/spinoko/blocks.md","filePath":"docs/spinoko/blocks.md"}'),n={name:"docs/spinoko/blocks.md"};function a(c,o,l,r,p,d){return s(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="spinoko-theme-blocks" tabindex="-1">Spinoko Theme Blocks <a class="header-anchor" href="#spinoko-theme-blocks" aria-label="Permalink to &quot;Spinoko Theme Blocks&quot;">​</a></h1><p>There are multiple blocks available for you to present your website information.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks.jpg" alt="Spinoko Blocks"></p><hr><h2 id="using-blocks" tabindex="-1">Using Blocks <a class="header-anchor" href="#using-blocks" aria-label="Permalink to &quot;Using Blocks&quot;">​</a></h2><p>Here are the blocks available in Spinoko theme:</p><ul><li>Casinos Table</li><li>Casinos Grid</li><li>Casino Finder</li><li>Casino Dropdown</li><li>Featured Casino</li><li>Games Grid</li><li>Game Finder</li><li>Recent Posts</li><li>Page Links</li><li>FAQs</li></ul><p>There are other blocks that are available in casino pages only: <a href="/docs/spinoko/casino-page-blocks">Casino Page Blocks</a></p><blockquote><p>Note that <a href="/docs/spinoko/casino-page-blocks#casino-bonuses-block">Casino Bonuses</a> and <a href="/docs/spinoko/casino-page-blocks#featured-bonus-block">Featured Bonus</a> blocks are available on all pages.</p></blockquote><h3 id="casinos-table-block" tabindex="-1">Casinos Table Block <a class="header-anchor" href="#casinos-table-block" aria-label="Permalink to &quot;Casinos Table Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-table-frontend.png" alt="spinoko-blocks-table"></p><p>To add a new table simply click on the <strong>+</strong> (Add block) sign and select <strong>Casinos Table</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new table edit section will appear. Click <strong>Add Casino</strong> to add as many casinos as you want. Select the style from the dropdown menu and whether to lazy load images or not, which is better left on for performance unless you have a reason to turn it off.</p><p>Casino Table block offers you multiple styles and options. You can display tables with default or compact layout, and you can display terms as a popover, as a link or as a plain text.</p><p><code>💁 since version 1.0.4</code> you can also enable <strong>table sorting</strong> for your tables regardless of their styles. It will add 5 buttons on top of the table to sort by: Name, Year, Rating, Bonus, Bonus %. You can customize the button texts in <strong>Customizer</strong> → <strong>Strings</strong> and you can change which buttons to display by following <a href="/docs/spinoko/how-to#how-to-change-table-sorting-keys">these steps</a>.</p><p><code>💁 since version 1.0.6</code> you can enable <strong>Highlight First Casino</strong> option and choose the highlight color (by default it&#39;s the theme primary color) and add an optional label to the 2nd casino.</p><p><code>💁 since version 1.0.8</code> you can enable <strong>Limit Casinos and Display a Load More Button</strong> option and select how many casinos to display initially. This option will hide the rest of the casinos and add a &quot;Load more Casinos&quot; button below the table. When a user clicks on the button the rest of the casinos are displayed as well.</p><p><code>💁 since version 2.0.0</code> you can add <strong>Casinos Games</strong> and <strong>Casino Countries</strong> to tables.</p><p><code>💁 since version 2.0.0</code> you can enable <strong>table filtering</strong> for your tables regardless of their styles. Casinos can be filtered by Country, Game, Game Provider, Payment Method, License.</p><p><code>💁 since version 2.8.4</code> you can add <strong>Casinos Payment Methods</strong> to tables.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-table-admin.jpg" alt="spinoko-blocks-table-admin"></p><p><code>💁 since version 2.5.8</code> you can select casinos by filtering them by category and/or tags.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-table-admin--tax.jpg" alt="spinoko-blocks-table-admin--tax"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the table in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual table as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="casinos-grid-block" tabindex="-1">Casinos Grid Block <a class="header-anchor" href="#casinos-grid-block" aria-label="Permalink to &quot;Casinos Grid Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-grid-frontend.png" alt="spinoko-blocks-grid"></p><p>To add a new grid simply click on the <strong>+</strong> (Add block) sign and select <strong>Casinos Grid</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new grid edit section will appear. Click <strong>Add Casino</strong> to add as many casinos. Select the number of columns and whether to lazy load images or not, which is better left on for performance unless you have a reason to turn it off.</p><p>Casino Grid block offers you multiple options for terms and conditions, you can display them as a popover, as a link or as a plain text.</p><p><code>💁 since version 1.0.8</code> you can enable <strong>Limit Casinos and Display a Load More Button</strong> option and select how many casinos to display initially. This option will hide the rest of the casinos and add a &quot;Load more Casinos&quot; button below the table. When a user clicks on the button the rest of the casinos are displayed as well.</p><p><code>💁 since version 2.0.0</code> you can add <strong>Casinos Games</strong> and <strong>Casino Countries</strong> to grids.</p><p><code>💁 since version 2.0.0</code> you can enable <strong>filtering</strong> for your grids regardless of their styles. Casinos can be filtered by Country, Game, Game Provider, Payment Method, License.</p><p><code>💁 since version 2.5.8</code> you can select casinos by filtering them by category and/or tags.</p><p><code>💁 since version 2.6.0</code> you can display casinos using a compact layout.</p><p><code>💁 since version 2.8.4</code> you can add <strong>Casinos Payment Methods</strong> to tables.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-grid-admin.jpg" alt="spinoko-blocks-grid-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the grid in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual grid as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="casino-finder-block" tabindex="-1">Casino Finder Block <a class="header-anchor" href="#casino-finder-block" aria-label="Permalink to &quot;Casino Finder Block&quot;">​</a></h3><p><code>💁 since version 2.5.0</code></p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-finder-frontend.jpg" alt="spinoko-blocks-casino-finder"></p><p>To add a new casino finder simply click on the + (Add block) sign and select <strong>Casino Finder</strong> in <strong>Spinoko Blocks</strong> section.</p><p>After that just adjust the labels displayed on the block and save the page.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-finder-admin.jpg" alt="spinoko-blocks-casino-finder-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the offer in your editor.</p><blockquote><p>Note that this block is not available in AMP mode.</p></blockquote><h3 id="casino-dropdown-block" tabindex="-1">Casino Dropdown Block <a class="header-anchor" href="#casino-dropdown-block" aria-label="Permalink to &quot;Casino Dropdown Block&quot;">​</a></h3><p><code>💁 since version 2.5.7</code></p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-dropdown-frontend.jpg" alt="spinoko-blocks-casino-dropdown"></p><p>To add a new casino dropdown simply click on the + (Add block) sign and select <strong>Casino Dropdown</strong> in <strong>Spinoko Blocks</strong> section.</p><p>After that just adjust the labels displayed on the block and save the page.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-dropdown-admin.jpg" alt="spinoko-blocks-casino-dropdown-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the offer in your editor.</p><blockquote><p>Note that this block is not available in AMP mode.</p></blockquote><h3 id="featured-casino-block" tabindex="-1">Featured Casino Block <a class="header-anchor" href="#featured-casino-block" aria-label="Permalink to &quot;Featured Casino Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-frontend.png" alt="spinoko-blocks-casino"></p><p>To add a new offer simply click on the <strong>+</strong> (Add block) sign and select <strong>Featured Casino</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new offer edit section will appear. Select a casino and configure the fields according to your preferences.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-casino-admin.png" alt="spinoko-blocks-casino-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the offer in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual block as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="games-grid-block" tabindex="-1">Games Grid Block <a class="header-anchor" href="#games-grid-block" aria-label="Permalink to &quot;Games Grid Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-games-grid-frontend.jpg" alt="spinoko-blocks-games-grid"></p><p>To add a new games grid simply click on the + (Add block) sign and select <strong>Games Grid</strong> in <strong>Spinoko Blocks</strong> section.</p><p>You can choose to display all games or selected ones.</p><p>If you choose all games, you need to also choose how many games to display per page. This will display a paginated list of games with a &quot;Load more games&quot; button at the bottom.</p><p>If you don&#39;t choose to display all games, you&#39;ll have an option to select only the ones you want to display.</p><p>Besides choosing the games, you can choose a layout for the grid (default and compact), also enable image lazy loading to improve page performance.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-games-grid-admin.jpg" alt="spinoko-blocks-games-grid-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the offer in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual block as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="game-finder-block" tabindex="-1">Game Finder Block <a class="header-anchor" href="#game-finder-block" aria-label="Permalink to &quot;Game Finder Block&quot;">​</a></h3><p><code>💁 since version 2.5.0</code></p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-game-finder-frontend.jpg" alt="spinoko-blocks-game-finder"></p><p>To add a new game finder simply click on the + (Add block) sign and select <strong>Game Finder</strong> in <strong>Spinoko Blocks</strong> section.</p><p>After that just adjust the labels displayed on the block and save the page.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-game-finder-admin.jpg" alt="spinoko-blocks-game-finder-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the offer in your editor.</p><blockquote><p>Note that this block is not available in AMP mode.</p></blockquote><h3 id="recent-posts-block" tabindex="-1">Recent Posts Block <a class="header-anchor" href="#recent-posts-block" aria-label="Permalink to &quot;Recent Posts Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-posts-frontend.png" alt="spinoko-blocks-recent-posts"></p><p>To add a new posts block simply click on the <strong>+</strong> (Add block) sign and select <strong>Recent Posts</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new recent posts edit section will appear. Select the number of posts to display and the post excerpt length. Or you can leave them blank for default values: 3 posts and 40 words.</p><p>You can also select a category to filter the posts or leave it blank to display posts from all categories.</p><p>The last option is the block style, there are currently 3 styles available.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-posts-admin.png" alt="spinoko-blocks-recent-posts-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the posts block in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual block as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="page-links-block" tabindex="-1">Page Links Block <a class="header-anchor" href="#page-links-block" aria-label="Permalink to &quot;Page Links Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-page-links-frontend.jpg" alt="spinoko-blocks-page-links"></p><p>To add a new posts block simply click on the <strong>+</strong> (Add block) sign and select <strong>Page Links</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new page links edit section will appear. Add as many pages as you want, and you&#39;re done.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-page-links-admin.jpg" alt="spinoko-blocks-page-links-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the posts block in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual block as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="faqs-block" tabindex="-1">FAQs Block <a class="header-anchor" href="#faqs-block" aria-label="Permalink to &quot;FAQs Block&quot;">​</a></h3><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-faq-frontend.png" alt="spinoko-blocks-faqs"></p><p>To add a new FAQs block simply click on the <strong>+</strong> (Add block) sign and select <strong>FAQs</strong> in <strong>Spinoko Blocks</strong> section.</p><p>In the content editor a new FAQs edit section will appear. For each one add the question and the answer and click <code>Add New</code> to add a new FAQ item.</p><p>Also set up how to display the FAQs by choosing whether they&#39;re open by default or not, can they be closed, 1 or 2 columns, etc.</p><p>Important: If you have more than one FAQ blocks on a single page, make sure to disable the rich snippets for all of them except one.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-faq-admin.png" alt="spinoko-blocks-faq-admin"></p><p>At the right side panel you can click on <strong>Switch to Preview</strong> to preview the FAQs block in your editor.</p><blockquote><p>Note that the preview may differ a little from the actual block as some WordPress and other plugin styles may be affecting it.</p></blockquote><h3 id="show-more-less-block" tabindex="-1">Show More/Less Block <a class="header-anchor" href="#show-more-less-block" aria-label="Permalink to &quot;Show More/Less Block&quot;">​</a></h3><p>To add a new Show More/Less block simply click on the + (Add block) sign and select Show More/Less in Spinoko Blocks section.</p><p>In the content editor a new edit section will appear. Add the visible and hidden text contents, the block style, as well as &quot;Show More&quot; and &quot;Show Less&quot; button texts.</p><p><img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-show-more-admin.jpg" alt="spinoko-blocks-show-more-less-admin"></p><p>There are 4 styles for this block:</p><ol><li><p>using a simple button <img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-show-more-option-1.jpg" alt="spinoko-blocks-show-more-less-option-1"></p></li><li><p>using a boxed layout with top and bottom borders and an arrow button <img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-show-more-option-2.jpg" alt="spinoko-blocks-show-more-less-option-2"></p></li><li><p>using a boxed layout using theme shadow and simple button <img src="https://media.dinomatic.com/images/docs/spinoko/spinoko-blocks-show-more-option-3.jpg" alt="spinoko-blocks-show-more-less-option-3"></p></li><li><p>no styles - plain text in case you want to add your own class names</p></li></ol>',111)])])}const m=e(n,[["render",a]]);export{h as __pageData,m as default};
